def flatten_dict(data: dict) -> dict:
    result = {}
    def visit(prefix: str, value: dict) -> None:
        for key, item in value.items():
            new_key = key if prefix == "" else f"{prefix}.{key}"
            if isinstance(item, dict):
                visit(new_key, item)
            else:
                result[new_key] = item
    visit("", data)
    return result
